          image: 'https://images.unsplash.com/photo-1668721039271-92f803d92af7?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w5MjI2ODB8MHwxfHNlYXJjaHw4fHxqYXBhbiUyMGxpZmVzdHlsZXxlbnwwfDB8fHwxNzc2MDY5OTc2fDA&ixlib=rb-4.1.0&q=80&w=1080',
          imageAlt: 'a few bills of money from a metal pole',
