          image: 'https://images.unsplash.com/photo-1505330622279-bf7d7fc918f4?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w5MjI2ODB8MHwxfHNlYXJjaHw3fHxkYWlseSUyMGxpZmV8ZW58MHwwfHx8MTc3NjM4MjYxM3ww&ixlib=rb-4.1.0&q=80&w=1080',
          imageAlt: 'MacBook Air beside gold-colored study lamp and spiral books',
