      { rank: 2, name: '冷凍フライドポテト', rating: 4.7, comment: 'たっぷり1kg入りで、おやつにも付け合わせにも大活躍する人気商品です。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%E5%86%B7%E5%87%8D%E3%83%95%E3%83%A9%E3%82%A4%E3%83%89%E3%83%9D%E3%83%86%E3%83%88/', amazonUrl: 'https://www.amazon.co.jp/s?k=%E5%86%B7%E5%87%8D%E3%83%95%E3%83%A9%E3%82%A4%E3%83%89%E3%83%9D%E3%83%86%E3%83%88' },
      { rank: 3, name: '冷凍讃岐うどん', rating: 4.5, comment: 'コシが強く本格的な味わい！冷凍庫に常備しておくと安心の逸品です。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%E5%86%B7%E5%87%8D%E8%AE%83%E5%B2%90%E3%81%86%E3%81%A9%E3%82%93/', amazonUrl: 'https://www.amazon.co.jp/s?k=%E5%86%B7%E5%87%8D%E8%AE%83%E5%B2%90%E3%81%86%E3%81%A9%E3%82%93' },
      { rank: 4, name: '冷凍ブロッコリー', rating: 4.3, comment: '彩りも栄養も満点！下処理不要でサッと使えるのが嬉しいポイントです。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%E5%86%B7%E5%87%8D%E3%83%96%E3%83%AD%E3%83%83%E3%82%B3%E3%83%AA%E3%83%BC/', amazonUrl: 'https://www.amazon.co.jp/s?k=%E5%86%B7%E5%87%8D%E3%83%96%E3%83%AD%E3%83%83%E3%82%B3%E3%83%AA%E3%83%BC' },
      { rank: 5, name: '冷凍むきえび', rating: 4.1, comment: '下処理済みのむきえびで、エビチリやパスタなど本格料理が手軽に楽しめます。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%E5%86%B7%E5%87%8D%E3%82%80%E3%81%8D%E3%81%88%E3%81%B3/', amazonUrl: 'https://www.amazon.co.jp/s?k=%E5%86%B7%E5%87%8D%E3%82%80%E3%81%8D%E3%81%88%E3%81%B3' }
