      { rank: 3, name: 'オーガニック温活ハーブティー「巡り美人ブレンド」', rating: 4.2, comment: '生姜やシナモン、ルイボスなどを配合。リラックス効果も高く、毎日続けやすいと評判です。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%E6%B8%A9%E6%B4%BB%E3%83%8F%E3%83%BC%E3%83%96%E3%83%86%E3%82%A3%E3%83%BC%E5%B7%A1%E3%82%8A%E7%BE%8E%E4%BA%BA%E3%83%96%E3%83%AC%E3%83%B3%E3%83%89/', amazonUrl: 'https://www.amazon.co.jp/s?k=%E6%B8%A9%E6%B4%BB%E3%83%8F%E3%83%BC%E3%83%96%E3%83%86%E3%82%A3%E3%83%BC%E5%B7%A1%E3%82%8A%E7%BE%8E%E4%BA%BA%E3%83%96%E3%83%AC%E3%83%B3%E3%83%89' },
      { rank: 4, name: '金時生姜発酵サプリ「ジンジャーパワーEX」', rating: 4.0, comment: '生姜の力を凝縮したサプリメント。手軽に体の中から温活をサポートしたい方におすすめです。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%E9%87%91%E6%99%82%E7%94%9F%E5%A7%9C%E7%99%BA%E9%85%B5%E3%82%B5%E3%83%97%E3%83%AA%E3%82%B8%E3%83%B3%E3%82%B8%E3%83%A3%E3%83%BC%E3%83%91%E3%83%AF%E3%83%BCEX/', amazonUrl: 'https://www.amazon.co.jp/s?k=%E9%87%91%E6%99%82%E7%94%9F%E5%A7%9C%E7%99%BA%E9%85%B5%E3%82%B5%E3%83%97%E3%83%AA%E3%82%B8%E3%83%B3%E3%82%B8%E3%83%A3%E3%83%BC%E3%83%91%E3%83%AF%E3%83%BCEX' },
      { rank: 5, name: 'シルク＆ウール重ね履きソックス「足元ほぐし」', rating: 3.8, comment: '吸湿性と保温性に優れた天然素材の組み合わせ。足元の冷えからしっかり守ってくれます。', affiliateUrl: 'https://search.rakuten.co.jp/search/mall/%EF%BC%86%E3%82%A6%E3%83%BC%E3%83%AB%E9%87%8D%E3%81%AD%E5%B1%A5%E3%81%8D%E3%82%BD%E3%83%83%E3%82%AF%E3%82%B9%E8%B6%B3%E5%85%83%E3%81%BB%E3%81%90%E3%81%97/', amazonUrl: 'https://www.amazon.co.jp/s?k=%EF%BC%86%E3%82%A6%E3%83%BC%E3%83%AB%E9%87%8D%E3%81%AD%E5%B1%A5%E3%81%8D%E3%82%BD%E3%83%83%E3%82%AF%E3%82%B9%E8%B6%B3%E5%85%83%E3%81%BB%E3%81%90%E3%81%97' }
